import React, { useState, useEffect } from 'react';
import { useModel } from '@umijs/max';
import { Card, Tag, Input, Switch, Button, message, Row, Col } from 'antd';
import { updateSettings } from '@/services/api';
import { t } from '@/global';
import { CloseOutlined } from '@ant-design/icons';
import MyModalConfirm from '@/components/Others/MyModalConfirm';

interface RelayProps {
  onRelayServersUpdate: (servers: string[], fetching: boolean) => void;
}

const Relay: React.FC<RelayProps> = ({ onRelayServersUpdate }) => {
  const { initialState, setInitialState } = useModel('@@initialState');
  const { settings: settingsList } = initialState!;

  const [relayServers, setRelayServers] = useState<string[]>([]);
  const [alwaysUseRelay, setAlwaysUseRelay] = useState(false);
  const [inputVisible, setInputVisible] = useState(false);
  const [inputValue, setInputValue] = useState('');

  useEffect(() => {
    fetchConfig();
  }, []);

  const fetchConfig = async () => {
    if (settingsList) {
      const relayServersSetting = settingsList.find((entry) => entry.key === 'RELAY_SERVERS');
      const alwaysUseRelaySetting = settingsList.find((entry) => entry.key === 'ALWAYS_USE_RELAY');
      if (relayServersSetting) {
        const servers = (relayServersSetting.value || "").split(',').filter(server => server !== '');
        setRelayServers(servers);
        onRelayServersUpdate(servers, false);
      }
      if (alwaysUseRelaySetting) {
        setAlwaysUseRelay(alwaysUseRelaySetting.value === 'TRUE' || alwaysUseRelaySetting.value === 'Y');
      }
    }
  };

  const handleAddServer = () => {
    setInputVisible(true);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setInputValue(e.target.value);
  };

  const processUrl = (url: string): string => {
    // remove http or https
    url = url.replace(/^https?:\/\//i, "");

    // IP/domian[:port]
    const pattern = /^(?<address>[\w.-]+)(:(?<port>\d+))?/;
    const match = url.match(pattern);

    if (match) {
      let result = match.groups?.address ?? "";
      if (match.groups?.port) {
        result += ":" + match.groups.port;
      }
      return result;
    } else {
      return "";
    }
  }

  const handleInputConfirm = async () => {
    const servers = inputValue.trim().split(',');
    const newRelayServers = [...relayServers];
    for (let server of servers) {
      server = server.trim();
      if (!server) continue;
      if (!newRelayServers.includes(server)) {
        const url = processUrl(server);
        if (url) {
          newRelayServers.push(url);
        }
      }
    }
    setInputVisible(false);
    setInputValue('');
    onRelayServersUpdate(newRelayServers, false);
    setRelayServers(newRelayServers);
    if (relayServers.join(',') !== newRelayServers.join(',')) {
      handleUpdateServers(newRelayServers);
    }
  };

  const handleCloseTag = async (removedTag: string) => {
    const newRelayServers = relayServers.filter((tag) => tag !== removedTag);
    console.log(newRelayServers);
    onRelayServersUpdate(newRelayServers, false);
    setRelayServers(newRelayServers);
    handleUpdateServers(newRelayServers);
  };

  const updateSettingsModel = async (key: string, value: string) => {
    const settings = settingsList || [];
    const i = settings.findIndex((entry) => entry.key === key);
    if (i >= 0) settings[i].value = value;
    else settings.push({ key, value });
    await setInitialState((s) => ({
      ...s,
      settings,
    }));
  };

  const handleAlwaysUseRelayChange = async (checked: boolean) => {
    setAlwaysUseRelay(checked);
    const value = checked ? 'TRUE' : 'FALSE';
    try {
      await updateSettings({ ALWAYS_USE_RELAY: value });
      message.success('Updated always use relay');
      await updateSettingsModel('ALWAYS_USE_RELAY', value);
    } catch (e) {
      message.error('Failed to update always use relay: ' + e);
    }
  };

  const handleUpdateServers = async (newRelayServers: String[]) => {
    const value = newRelayServers.join(',');
    try {
      await updateSettings({ RELAY_SERVERS: value });
      message.success('Updated relay servers');
      await updateSettingsModel('RELAY_SERVERS', value);
    } catch (e) {
      message.error('Failed to update relay servers: ' + e);
    }
  };

  function confirmableTag(label: string, onConfirm: () => void) {
    return (
      <Tag><>{label}<MyModalConfirm
        title={t('deleteConfirm', true, 'Are you sure to delete?')}
        onConfirm={() => {
          onConfirm();
        }}
        okText="Yes"
        cancelText="No"
      >
        <CloseOutlined style={{ marginLeft: 6 }} />
      </MyModalConfirm></></Tag>
    );
  }

  return (
    <Card title={t('pages.Settings.GeoOverride.RelaySettings', true, 'Relay Settings')}>
      <Row>
        <Col span={4}>
          <span style={{ marginRight: 8 }}>{t('pages.Settings.GeoOverride.RelayServers', true, 'Relay Servers')}: </span>
        </Col>
        <Col span={20}>
          <div style={{ display: 'flex', flexWrap: 'wrap', alignItems: 'center' }}>
            {relayServers.map((server) => (
              confirmableTag(server, () => handleCloseTag(server))
            ))}
            {inputVisible ? (
              <Input
                type="text"
                size="small"
                autoFocus
                value={inputValue}
                onChange={handleInputChange}
                onBlur={() => handleInputConfirm()}
                onPressEnter={() => handleInputConfirm()}
                style={{ width: 200, margin: "6px 0" }}
                placeholder={"<domain/ip>[:port]"}
              />
            ) : (
              <Button onClick={handleAddServer} size="small">
                <strong>+</strong>
              </Button>
            )}
          </div>
        </Col>
      </Row>
      <br />
      <Row>
        <Col span={4}>
          <span>{t('pages.Settings.GeoOverride.AlwaysUseRelay', true, 'Always Use Relay')}:</span>
        </Col>
        <Col span={20}>
          <Switch checked={alwaysUseRelay} onChange={handleAlwaysUseRelayChange} />
        </Col>
      </Row>
    </Card>
  );
};

export default Relay;
