import React from 'react';
import Relay from './Relay';
import GeoOverrideCard from './GeoOverride';
import { PageContainer } from '@ant-design/pro-layout';
import { Breadcrumb } from 'antd';
import { t } from '@/global';

const Integration = () => {
  const [relayServers, setRelayServers] = React.useState<string[]>([]);
  const [isFetching, setIsFetching] = React.useState(true);
  const handleRelayServersUpdate = (servers: string[], fetching: boolean) => {
    setRelayServers(servers);
    setIsFetching(fetching);
  };

  return (
    <PageContainer
      breadcrumbRender={() => (
        <Breadcrumb items={[
          { title: t('menu.Settings', true) },
          { title: t('menu.Settings.Relay', true) },
        ]} />
      )}
    >
      <Relay onRelayServersUpdate={handleRelayServersUpdate} />
      <br />
      {relayServers.length > 1 && !isFetching ? <GeoOverrideCard /> : <></>}
    </PageContainer>
  );
};

export default Integration;
