import React, { useState, useEffect } from 'react';
import { Card, Button, Table, Space, Modal, Input, InputNumber, Form, message, Typography } from 'antd';
import { getAllGeoOverrides, updateGeoOverride, deleteGeoOverrides, executeCommand, getGeofileTimestamp } from '@/services/api';
import { DeleteOutlined, ReloadOutlined, ClockCircleOutlined } from '@ant-design/icons';
import { API } from '@/services/typings';
import { t } from '@/global';
import MyModalConfirm from '@/components/Others/MyModalConfirm';

const GeoOverrideCard = () => {
  const [geoOverrides, setGeoOverrides] = useState<API.GeoOverride[]>([]);
  const [selectedRowKeys, setSelectedRowKeys] = useState<React.Key[]>([]);
  const [modalVisible, setModalVisible] = useState(false);
  const [editOverride, setEditOverride] = useState<API.GeoOverride | null>(null);
  const [geofileTimestamp, setGeofileTimestamp] = useState('');
  const [geofileFetchError, setGeofileFetchError] = useState("");

  const rowSelection = {
    selectedRowKeys,
    onChange: (selectedRowKeys: React.Key[]) => {
      setSelectedRowKeys(selectedRowKeys);
    },
  };

  useEffect(() => {
    fetchGeoOverrides();
    fetchGeofileTimestamp();
  }, []);

  const fetchGeoOverrides = async () => {
    const data = await getAllGeoOverrides();
    setGeoOverrides(data);
  };

  const fetchGeofileTimestamp = async () => {
    try {
      const timestamp = await getGeofileTimestamp();
      setGeofileTimestamp(timestamp);
      setGeofileFetchError('');
    } catch (error) {
      setGeofileFetchError('' + error);
    }
  };

  const handleDeleteSelected = async () => {
    try {
      await deleteGeoOverrides(selectedRowKeys as string[]);
      message.success('Selected geo overrides deleted successfully');
      fetchGeoOverrides();
      setSelectedRowKeys([]);
    } catch (e) {
      message.error('Failed to delete selected geo overrides: ' + e);
    }
  };

  const handleReloadGeo = async () => {
    await executeCommand('reload-geo');
    message.success(t('pages.Settings.GeoOverride.reloadSuccess', false, 'Geo database reloaded successfully'));
  };

  const handleOpenEditModal = (override: API.GeoOverride | null) => {
    setEditOverride(override);
    setModalVisible(true);
  };

  const handleModalCancel = () => {
    setModalVisible(false);
  };

  const handleModalSave = async (values: API.GeoOverride) => {
    setModalVisible(false);
    let override: API.GeoOverride | undefined;
    if (editOverride) {
      override = { ...editOverride, ...values };
    } else {
      override = values;
    }
    const index = geoOverrides.findIndex(
      (item) => item.relay_server === override?.relay_server
    );
    if (index !== -1) {
      geoOverrides[index] = override!;
    } else {
      geoOverrides.push(override!);
    }
    try {
      await updateGeoOverride(geoOverrides);
      message.success('Geo override updated successfully');
      fetchGeoOverrides();
    } catch (e) {
      message.error('Failed to update geo override:' + e);
    }
  };

  const handleDeleteOverride = async (relay_server: string) => {
    try {
      await deleteGeoOverrides([relay_server]);
      message.success('Geo override deleted successfully');
      fetchGeoOverrides();
    } catch (e) {
      message.error('Failed to delete geo override: ' + e);
    }
  };

  const handleTestGeo = async (data: any) => {
    if (!data.ip1 || !data.ip2) return;
    const command = `test-geo ${data.ip1} ${data.ip2}`;
    const result = await executeCommand(command);
    message.success(result);
  };

  return (
    (<Card
      title={t('pages.Settings.GeoOverride.title', true, 'Geo Override')}
      extra={
        <Space>
          <ClockCircleOutlined />
          <Typography.Text type="secondary">{geofileFetchError ? t('pages.Settings.GeoOverride.geofileFetchFailed', true, 'Geofile information fetch failed') + ': ' + geofileFetchError : `${geofileTimestamp}`}</Typography.Text>
        </Space>
      }
    >
      <Space style={{ marginBottom: 16 }}>
        <Button onClick={handleReloadGeo} icon={<ReloadOutlined />}>
          {t('pages.Settings.GeoOverride.reloadGeo', true, 'Reload Geo')}
        </Button>
        <Button onClick={() => handleOpenEditModal(null)}>{t('Add')}</Button>
        <MyModalConfirm
          title={t('pages.Settings.GeoOverride.deleteSelectedConfirm', true, 'Are you sure to delete selected overrides?')}
          onConfirm={handleDeleteSelected}
          okText="Yes"
          cancelText="No"
        >
          <Button danger icon={<DeleteOutlined />}>
            {t('Delete')}
          </Button>
        </MyModalConfirm>
      </Space>
      <Table
        dataSource={geoOverrides}
        rowSelection={rowSelection}
        rowKey="relay_server"
        columns={[
          {
            title: t('pages.Settings.GeoOverride.relayServer', true, 'Relay Server'),
            dataIndex: 'relay_server',
            key: 'relay_server',
          },
          {
            title: t('pages.Settings.GeoOverride.latitude', true, 'Latitude'),
            dataIndex: 'latitude',
            key: 'latitude',
          },
          {
            title: t('pages.Settings.GeoOverride.longitude', true, 'Longitude'),
            dataIndex: 'longitude',
            key: 'longitude',
          },
          {
            title: t('Action'),
            dataIndex: 'actions',
            key: 'actions',
            render: (_, record: API.GeoOverride) => (
              <Space>
                <Button onClick={() => handleOpenEditModal(record)}>{t('Edit')}</Button>
                <MyModalConfirm
                  title={t('pages.Settings.GeoOverride.deleteConfirm', true, 'Are you sure to delete this override?')}
                  onConfirm={() => handleDeleteOverride(record.relay_server || "")}
                  okText="Yes"
                  cancelText="No"
                >
                  <Button danger>{t('Delete')}</Button>
                </MyModalConfirm>
              </Space>
            ),
          },
        ]}
      />
      {modalVisible && <Modal
        open={modalVisible}
        title={editOverride ? t('pages.Settings.GeoOverride.editGeoOverride', true, 'Edit Geo Override') : t('pages.Settings.GeoOverride.addGeoOverride', true, 'Add Geo Override')}
        onCancel={handleModalCancel}
        footer={null}
      >
        <Form
          initialValues={editOverride ?? undefined}
          onFinish={handleModalSave}
          layout="vertical"
        >
          <Form.Item
            label={t('pages.Settings.GeoOverride.relayServer', true, 'Relay Server')}
            name="relay_server"
            rules={[
              { required: true, whitespace: true, message: t('pages.Settings.GeoOverride.ipOrDomainRequired', true, 'Please input the IP or domain') }
            ]}
          >
            {editOverride ? editOverride.relay_server : <Input />}
          </Form.Item>
          <Form.Item
            label={t('pages.Settings.GeoOverride.latitude', true, 'Latitude')}
            name="latitude"
            rules={[
              { required: true, message: t('pages.Settings.GeoOverride.latitudeRequired', true, 'Please input the latitude') }
            ]}
          >
            <InputNumber min={-90} max={90} />
          </Form.Item>
          <Form.Item
            label={t('pages.Settings.GeoOverride.longitude', true, 'Longitude')}
            name="longitude"
            rules={[
              { required: true, message: t('pages.Settings.GeoOverride.longitudeRequired', true, 'Please input the longitude') }
            ]}
          >
            <InputNumber min={-180} max={180} />
          </Form.Item>
          <Form.Item>
            <Button htmlType="submit">{t('Submit')}</Button>
          </Form.Item>
        </Form>
      </Modal>}
      <br />
      <Form layout="inline" onFinish={handleTestGeo}>
        <Form.Item label="IP1" name="ip1">
          <Input />
        </Form.Item>
        <Form.Item label="IP2" name="ip2">
          <Input />
        </Form.Item>
        <Button htmlType="submit" type="primary" style={{ marginRight: 8 }}>{t('pages.Settings.GeoOverride.getRelayServer', true, 'Get Relay Server')}</Button>
      </Form>
    </Card>)
  );
};

export default GeoOverrideCard;
